//
// Compilation-time benchmark.
//
// This translation unit is NOT meant to measure runtime — it is meant to be
// *compiled* under a profiler (clang -ftime-trace) to measure how long the
// recursive template instantiation takes for an entity with a deep graph of
// foreign-key relationships.
//
// `Table99` (generated by ddl2cpp from the schema produced by
// CreateDatabase.py) transitively pulls in a large chain of related tables.
// Instantiating the DataMapper machinery for it — query building and, above
// all, recursive relation auto-loading — is the heavy work we want to time.
//
// The DataMapper calls below live behind `if (false)` on purpose: the bodies
// are still fully type-checked and the templates are still instantiated (which
// is all the compiler-time benchmark cares about), but the program never opens
// a database connection, so it is safe to build/link without any DB present.
//
// See how_to.md for the measurement workflow.

#if defined(LIGHTWEIGHT_CXX26_REFLECTION)
    /// @brief marco to define a member to the structure, in case of C++26 reflection this
    /// will create reflection, in case of C++20 reflection this will create a member pointer
    #define Member(x) ^^x

#else
    /// @brief marco to define a member to the structure, in case of C++26 reflection this
    /// will create reflection, in case of C++20 reflection this will create a member pointer
    #define Member(x) &x
#endif

#include "entities/Table99.hpp"

#include <cstdlib>

int main()
{
    // Compiled but never executed: forces instantiation of the query builder
    // and the recursive relation-auto-loading machinery for the whole graph
    // reachable from Table99, without requiring a live database.
    if (auto dm = Lightweight::DataMapper(); false)
    {
        for (auto& entry: dm.Query<Table99>().All())
            dm.ConfigureRelationAutoLoading(entry);
    }

    return EXIT_SUCCESS;
}
